// Product Storefront product detail (spec §02). Money fields (basePrice, colors[].priceDelta, options[].priceDelta) are raw int-VND — the client formats via @lumin/core (always-must #2). images[0] is the card cover (sprite-first, ADR-007). No productType in Phase 1 (D-P1-1).
type Product struct {
	// BasePrice Starting price in int-VND (>= 0); options may add to it.
	BasePrice  int64              `json:"basePrice"`
	CategoryId openapi_types.UUID `json:"categoryId"`
	Colors     []Color            `json:"colors"`
	CreatedAt  time.Time          `json:"createdAt"`

	// Description Markdown stored as text (spec §02 richtext).
	Description string `json:"description"`

	// Dimensions Product bounding size in millimetres (spec §02; displayed "180 × 180 × 240 mm").
	Dimensions Dimensions         `json:"dimensions"`
	Id         openapi_types.UUID `json:"id"`

	// Images Shop photos; images[0] is the card cover (sprite-first, ADR-007). May be empty.
	Images []string `json:"images"`

	// Material Print material (spec §02; open-ended TEXT+CHECK, ADR-028 — not a wire enum).
	Material string `json:"material"`

	// Model3dUrl .glb URL for the on-demand model viewer; empty string when none.
	Model3dUrl string   `json:"model3dUrl"`
	Name       string   `json:"name"`
	Options    []Option `json:"options"`

	// Parts Named parts (ADR-037), each grouping a subset of colors[] via Color.partId. Empty = a single-piece product (flat colours). The customer picks one colour per part.
	Parts []Part `json:"parts"`

	// RatingAvg Denormalized average rating; null until the first review.
	RatingAvg *float32 `json:"ratingAvg"`

	// ReviewCount Denormalized review count (spec §02).
	ReviewCount int `json:"reviewCount"`

	// Slug Unique URL slug (spec §02).
	Slug string `json:"slug"`

	// Status Product lifecycle (spec §02, Postgres `product_status`). The detail read returns `active` only.
	Status ProductStatus `json:"status"`
}

// ProductCard Lightweight catalog-list projection of a product (spec §02) — the fields a grid card needs, WITHOUT colors/options/description body (the list avoids the per-product reads the detail read makes → no N+1). basePrice is raw int-VND; images[0] is the card cover (sprite-first, ADR-007). Only ACTIVE products are ever listed, so status is implied and omitted.
type ProductCard struct {
	// BasePrice Starting price in int-VND (>= 0).
	BasePrice  int64              `json:"basePrice"`
	CategoryId openapi_types.UUID `json:"categoryId"`
	Id         openapi_types.UUID `json:"id"`

	// Images Shop photos; images[0] is the card cover (ADR-007). May be empty.
	Images []string `json:"images"`
	Name   string   `json:"name"`

	// RatingAvg Denormalized average rating; null until the first review.
	RatingAvg *float32 `json:"ratingAvg"`

	// ReviewCount Denormalized review count (spec §02).
	ReviewCount int `json:"reviewCount"`

	// Slug Unique URL slug (spec §02).
	Slug string `json:"slug"`
}

// ProductInput Create/replace body for a product (P3-j, owner-only). Same editable fields as Product MINUS the server/pipeline-owned ones: no id/createdAt/ratingAvg/reviewCount (server-owned), no colors/options (managed via their own nested endpoints), and no model3dUrl (owned by the asset pipeline, P3-j-b — the editor form can never set or blank it). basePrice is raw int-VND (always-must #2). description and images are optional (default "" / []).
